#include <iostream>
#include <queue>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;
    int maze[100][100];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cin >> maze[i][j];
        }
    }
    int startX, startY, endX, endY;
    cin >> startX >> startY >> endX >> endY;

    int dx[] = {0, 0, 1, -1};
    int dy[] = {1, -1, 0, 0};

    queue<pair<int, int>> q;
    q.push({startX, startY});
    maze[startX][startY] = 1;
    int steps = 0;

    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; i++) {
            auto curr = q.front();
            q.pop();
            if (curr.first == endX && curr.second == endY) {
                cout << steps << endl;
                return 0;
            }
            for (int j = 0; j < 4; j++) {
                int nx = curr.first + dx[j];
                int ny = curr.second + dy[j];
                if (nx >= 0 && nx < n && ny >= 0 && ny < m && maze[nx][ny] == 0) {
                    maze[nx][ny] = 1;
                    q.push({nx, ny});
                }
            }
        }
        steps++;
    }
    cout << -1 << endl;
    return 0;
}
